INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("クローチェ", 1, "2023/06/30 12:00:00", 1, "いらっしゃいませっ♪\nキャラバンコインを使って\n買い物ができますよっ！", -470.0, 126401, 1, 2002, 1.47, 0.0, 2, 10001, "2023/09/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("クローチェ", 2, "2023/06/30 12:00:00", 2, "素敵な品が揃ってるので\nたーっくさん買っていって\nくださいねっ♪", -470.0, 126401, 1, 2002, 2.15, 0.0, 1, 10002, "2023/09/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ライラエル", 1, "2023/06/30 12:00:00", 2, "ショップへようこそ\nキャラバンコインはこちら\nで買い物に使えますよ", -470.0, 126501, 1, 2002, 0.0, 0.0, 2, 10003, "2023/09/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ライラエル", 2, "2023/06/30 12:00:00", 1, "こちらのショップで\n買い物をして、素敵な\n旅を楽しんでくださいね", -470.0, 126501, 1, 2002, 0.0, 0.0, 1, 10004, "2023/09/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("リンド", 1, "2023/09/15 15:00:00", 2, "いらっしゃいませ\nキャラバンコインを使って\nお買い物ができますよ", -470.0, 127702, 2, 2002, 0.0, 0.0, 2, 10005, "2023/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("リンド", 2, "2023/09/15 15:00:00", 2, "ショップの掃除は完璧です\n姫さま直営のお店として\n当然のことですから", -470.0, 127702, 2, 2002, 0.0, 0.0, 2, 10006, "2023/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ヴルム", 1, "2023/09/15 15:00:00", 1, "ショップへようこそ\nキャラバンコインと品物を\n交換できるんで、よければ", -470.0, 127802, 2, 2002, 0.0, 0.0, 1, 10007, "2023/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ヴルム", 2, "2023/09/15 15:00:00", 2, "なんで店番なんか…\nま、やりますけど\n好きな品物をどうぞ", -470.0, 127802, 2, 2002, 6.5, 0.0, 1, 10008, "2023/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("アネモネ", 1, "2023/12/15 15:00:00", 2, "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば", -470.0, 129602, 3, 2002, 0.0, 0.0, 1, 10009, "2024/03/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("アネモネ", 2, "2023/12/15 15:00:00", 2, "──もっと笑顔がほしい？\nいくらコインを積まれても\n売れない物はありますから", -470.0, 129602, 3, 2002, 0.0, 0.0, 1, 10010, "2024/03/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ネフィ=ネラ", 1, "2023/12/15 15:00:00", 1, "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう", -470.0, 129701, 3, 2002, 0.0, 0.0, 1, 10011, "2024/03/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ネフィ=ネラ", 2, "2023/12/15 15:00:00", 2, "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす", -470.0, 129701, 3, 2002, 6.2, 0.0, 1, 10012, "2024/03/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("カノン", 1, "2024/03/15 15:00:00", 3, "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ", -470.0, 130301, 4, 2002, 3.1, 0.0, 5, 10013, "2024/06/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("カノン", 2, "2024/03/15 15:00:00", 3, "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？", -470.0, 130301, 4, 2002, 6.15, 0.0, 2, 10014, "2024/06/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ナーナ", 1, "2024/03/15 15:00:00", 2, "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー", -470.0, 130401, 4, 2002, 0.0, 0.0, 2, 10015, "2024/06/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ナーナ", 2, "2024/03/15 15:00:00", 2, "甘いのくれたら、\nお礼にナーナの拾った\n松ぼっくりあげちゃうよ！", -470.0, 130401, 4, 2002, 3.35, 0.0, 1, 10016, "2024/06/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ホウオウ", 1, "2024/06/15 15:00:00", 1, "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう", -470.0, 130502, 5, 2002, 0.0, 0.0, 1, 10017, "2024/09/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ホウオウ", 2, "2024/06/15 15:00:00", 2, "ほーちゃんと呼ぶ権利は\n売っていませんよ？\n騎士さんへの、特別です！", -470.0, 130502, 5, 2002, 3.18, 0.0, 1, 10018, "2024/09/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ホウオウ", 3, "2024/06/15 15:00:00", 4, "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！", -470.0, 130503, 5, 2002, 0.0, 0.0, 4, 10019, "2024/09/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ネア", 1, "2024/06/15 15:00:00", 1, "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で", -470.0, 123301, 5, 2002, 4.9, 0.0, 2, 10020, "2024/09/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ネア", 2, "2024/06/15 15:00:00", 1, "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡", -470.0, 123301, 5, 2002, 4.8, 0.0, 2, 10021, "2024/09/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("カリザ", 1, "2024/09/15 15:00:00", 3, "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！", -470.0, 133301, 6, 2002, 4.922, 0.0, 1, 10022, "2024/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("カリザ", 2, "2024/09/15 15:00:00", 3, "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！", -470.0, 133301, 6, 2002, 9.638, 0.0, 5, 10023, "2024/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ミーア", 1, "2024/09/15 15:00:00", 1, "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す", -470.0, 133401, 6, 2002, 2.88, 0.0, 2, 10024, "2024/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ミーア", 2, "2024/09/15 15:00:00", 5, "私の抜け殻とか、\n需要ありますかね～…\nって冗談ですよ、冗談！", -470.0, 133401, 6, 2002, 4.818, 0.0, 1, 10025, "2024/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("グレイス", 1, "2024/12/15 15:00:00", 2, "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？", -470.0, 133002, 7, 2002, 1.78, 0.0, 1, 10026, "2025/03/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("グレイス", 2, "2024/12/15 15:00:00", 1, "商品をお買い上げ毎に\nグレイスちゃんポイントを\n差し上げます。嘘ですが", -470.0, 133002, 7, 2002, 6.15, 0.0, 7, 10027, "2025/03/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ヴァイオレット", 1, "2024/12/15 15:00:00", 6, "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？", -470.0, 133102, 7, 2002, 4.28, 0.0, 2, 10028, "2025/03/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ヴァイオレット", 2, "2024/12/15 15:00:00", 1, "じめじめした商品は\nございませんので\n安心してお買い求め下さい", -470.0, 133102, 7, 2002, 0.0, 0.0, 1, 10029, "2025/03/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ルルィ", 1, "2025/03/15 15:00:00", 2, "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！", -470.0, 136902, 8, 2002, 5.53, 0.0, 1, 10030, "2025/06/23 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ルルィ", 2, "2025/03/15 15:00:00", 9, "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…", -470.0, 136902, 8, 2002, 6.05, 0.0, 7, 10031, "2025/06/23 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("デュラン", 1, "2025/03/15 15:00:00", 2, "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ", -470.0, 137001, 8, 2002, 0.0, 0.0, 1, 10032, "2025/06/23 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("デュラン", 2, "2025/03/15 15:00:00", 2, "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？", -470.0, 137001, 8, 2002, 0.0, 0.0, 1, 10033, "2025/06/23 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("サツキ", 1, "2025/06/16 15:00:00", 2, "おう\n好きなもん持ってきな", -470.0, 135902, 9, 2002, 0.0, 0.0, 2, 10034, "2025/09/23 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("サツキ", 2, "2025/06/16 15:00:00", 1, "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ", -470.0, 135902, 9, 2002, 4.935, 0.0, 6, 10035, "2025/09/23 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ユキノ", 1, "2025/06/16 15:00:00", 2, "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？", -470.0, 135802, 9, 2002, 7.441, 0.0, 5, 10036, "2025/09/23 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ユキノ", 2, "2025/06/16 15:00:00", 7, "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？", -470.0, 135802, 9, 2002, 0.0, 0.0, 7, 10037, "2025/09/23 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("クルル", 1, "2025/09/16 15:00:00", 2, "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪", -470.0, 130901, 10, 2002, 2.295, 0.0, 2, 10038, "2025/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("クルル", 2, "2025/09/16 15:00:00", 1, "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？", -470.0, 130901, 10, 2002, 6.281, 0.0, 6, 10039, "2025/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ヴォルガーノ", 1, "2025/09/16 15:00:00", 2, "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！", -470.0, 137701, 10, 2002, 5.549, 0.0, 1, 10040, "2025/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ヴォルガーノ", 2, "2025/09/16 15:00:00", 3, "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！", -470.0, 137701, 10, 2002, 2.64, 0.0, 6, 10041, "2025/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ライラエル", 1, "2025/12/15 15:00:00", 7, "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？", -470.0, 132801, 11, 2002, 7.642, 0.0, 4, 10042, "2026/03/23 11:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ライラエル", 2, "2025/12/15 15:00:00", 1, "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い", -470.0, 132802, 11, 2002, 0.0, 0.0, 1, 10043, "2026/03/23 11:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("クローチェ", 1, "2025/12/15 15:00:00", 1, "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪", -470.0, 134502, 11, 2002, 0.0, 0.0, 1, 10044, "2026/03/23 11:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("クローチェ", 2, "2025/12/15 15:00:00", 2, "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ", -470.0, 134501, 11, 2002, 3.72, 0.0, 1, 10045, "2026/03/23 11:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ネフィ＝ネラ", 1, "2026/03/16 12:00:00", 2, "番頭も、飯事の如き営み\nなれば。愛らしき稚児らで\n千客万来といきませぬか喃", -470.0, 138201, 12, 2002, 4.991, 0.0, 1, 10046, "2026/06/22 11:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("ネフィ＝ネラ", 2, "2026/03/16 12:00:00", 1, "国を営むに金子は必須也…\nどうか御恵みくだしゃんせ\n誠心を以て報恩致しまする", -470.0, 138201, 12, 2002, 3.877, 0.0, 4, 10047, "2026/06/22 11:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("アラクネ", 1, "2026/03/16 12:00:00", 4, "あぅっ…！　天井が低くて\n頭をぶつけてしまって…\nわたしが、大きいだけ…？", -470.0, 136001, 12, 2002, 1.71, 0.0, 6, 10048, "2026/06/22 11:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES ("アラクネ", 2, "2026/03/16 12:00:00", 5, "いらっしゃいませ騎士さま\nくつろいでいって下さいね\nもし叶うなら…永遠に…", -470.0, 136001, 12, 2002, 5.32, 0.0, 2, 10049, "2026/06/22 11:59:59");
